<?php namespace App\Services\System; use Illuminate\Support\Facades\Artisan; use Illuminate\Support\Facades\Log; use Illuminate\Support\Facades\Cache; use Illuminate\Support\Facades\DB; class MaintenanceService { protected $logger; public function __construct() { $this->logger = Log::channel('daily'); } public function enableMaintenanceMode(array $data = []): bool { try { Artisan::call('down', $data); $this->logger->info('تم تفعيل وضع الصيانة للنظام بنجاح.'); return true; } catch (\Exception $e) { $this->logger->error('فشل في تفعيل وضع الصيانة: ' . $e->getMessage()); return false; } } public function disableMaintenanceMode(): bool { try { Artisan::call('up'); $this->logger->info('تم إيقاف وضع الصيانة وعودة النظام للعمل.'); return true; } catch (\Exception $e) { $this->logger->error('فشل في إيقاف وضع الصيانة: ' . $e->getMessage()); return false; } } public function checkSystemHealth(): array { $health = ['database' => false, 'cache' => false, 'storage' => is_writable(storage_path())]; try { DB::connection()->getPdo(); $health['database'] = true; } catch (\Exception $e) { $this->logger->warning('فحص النظام: تعذر الاتصال بقاعدة البيانات.'); } try { Cache::store()->put('health_check', 'ok', 10); $health['cache'] = true; } catch (\Exception $e) { $this->logger->warning('فحص النظام: تعذر الاتصال بذاكرة الكاش.'); } return $health; } public function generateResourceReport(): array { $report = [ 'memory_usage' => memory_get_usage(true) / 1024 / 1024 . ' MB', 'peak_memory' => memory_get_peak_usage(true) / 1024 / 1024 . ' MB', 'timestamp' => now()->toDateTimeString(), ]; $this->logger->info('تم توليد تقرير استهلاك الموارد: ' . json_encode($report)); return $report; } public function performFullSystemAudit(): void { $this->logger->info('بدء عملية التدقيق الدوري الشامل للنظام.'); $health = $this->checkSystemHealth(); if (!in_array(false, $health)) { $this->logger->info('نتائج التدقيق: النظام يعمل بحالة ممتازة.'); } else { $this->logger->alert('تحذير: تم اكتشاف مشاكل في مكونات النظام.', $health); } } }